struct SkenionFrame {
  resolution: vec2<f32>,
  time: f32,
  frame: u32,
}

@group(0) @binding(0)
var<uniform> skenion: SkenionFrame;

struct VertexOut {
  @builtin(position) position: vec4<f32>,
}

@vertex
fn vs_main(@builtin(vertex_index) vertex_index: u32) -> VertexOut {
  var positions = array<vec2<f32>, 3>(
    vec2<f32>(-1.0, -3.0),
    vec2<f32>(-1.0,  1.0),
    vec2<f32>( 3.0,  1.0)
  );

  var out: VertexOut;
  out.position = vec4<f32>(positions[vertex_index], 0.0, 1.0);
  return out;
}

@fragment
fn fs_main() -> @location(0) vec4<f32> {
  let uv = skenion.resolution / max(skenion.resolution.x, skenion.resolution.y);
  let pulse = 0.5 + 0.5 * sin(skenion.time + f32(skenion.frame) * 0.015);
  return vec4<f32>(0.1 + uv.x * 0.4, pulse, 0.35 + uv.y * 0.4, 1.0);
}
